'use client';
import React from 'react';
import {
  Container,
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
} from '@mui/material';
import {
  Phone,
  Email,
  LocationOn,
  Schedule,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import ContactForm from '@/components/ContactForm/ContactForm';

const Contact = () => {
  const contactInfo = [
    {
      icon: <Phone sx={{ fontSize: 40 }} />,
      title: 'Phone',
      details: ['+91 98765 43210', '+91 98765 43211'],
      color: '#FFA500',
    },
    {
      icon: <Email sx={{ fontSize: 40 }} />,
      title: 'Email',
      details: ['info@solareenergy.com', 'support@solareenergy.com'],
      color: '#2B7A0B',
    },
    {
      icon: <LocationOn sx={{ fontSize: 40 }} />,
      title: 'Address',
      details: [
        'Pune, Maharashtra',
        'India',
      ],
      color: '#1E293B',
    },
    {
      icon: <Schedule sx={{ fontSize: 40 }} />,
      title: 'Business Hours',
      details: ['Mon - Sat: 9:00 AM - 6:00 PM', 'Sunday: Closed'],
      color: '#FFA500',
    },
  ];

  return (
    <Box sx={{ pt: { xs: 8, md: 10 }, pb: 8 }}>
      {/* Hero Section */}
      <Box
        sx={{
          bgcolor: 'primary.main',
          color: 'white',
          py: 8,
          textAlign: 'center',
        }}
      >
        <Container maxWidth="md">
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <Typography variant="h1" sx={{ fontWeight: 800, mb: 3 }}>
              Contact Us
            </Typography>
            <Typography variant="h5" sx={{ opacity: 0.9 }}>
              Get in touch with us for free consultation and quotes
            </Typography>
          </motion.div>
        </Container>
      </Box>

      <Container maxWidth="xl" sx={{ mt: 8 }}>
        <Grid container spacing={4}>
          {/* Contact Form */}
          <Grid item xs={12} md={7}>
            <motion.div
              initial={{ opacity: 0, x: -30 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6 }}
            >
              <Typography variant="h3" sx={{ fontWeight: 800, mb: 4 }}>
                Send us a Message
              </Typography>
              <ContactForm />
            </motion.div>
          </Grid>

          {/* Contact Information */}
          <Grid item xs={12} md={5}>
            <motion.div
              initial={{ opacity: 0, x: 30 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6 }}
            >
              <Typography variant="h3" sx={{ fontWeight: 800, mb: 4 }}>
                Get in Touch
              </Typography>
              <Grid container spacing={3}>
                {contactInfo.map((info, index) => (
                  <Grid item xs={12} key={index}>
                    <Card sx={{ p: 3 }}>
                      <Box
                        sx={{
                          display: 'flex',
                          alignItems: 'center',
                          gap: 2,
                          mb: 2,
                        }}
                      >
                        <Box
                          sx={{
                            color: info.color,
                            display: 'flex',
                            alignItems: 'center',
                          }}
                        >
                          {info.icon}
                        </Box>
                        <Typography variant="h6" sx={{ fontWeight: 700 }}>
                          {info.title}
                        </Typography>
                      </Box>
                      {info.details.map((detail, idx) => (
                        <Typography
                          key={idx}
                          variant="body2"
                          color="text.secondary"
                          sx={{ ml: 7 }}
                        >
                          {detail}
                        </Typography>
                      ))}
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </motion.div>
          </Grid>
        </Grid>

        {/* Map Section */}
        <Box sx={{ mt: 8 }}>
          <Typography variant="h3" sx={{ fontWeight: 800, mb: 4, textAlign: 'center' }}>
            Find Us
          </Typography>
          <Box
            sx={{
              height: 400,
              bgcolor: 'background.default',
              borderRadius: 4,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '2px dashed',
              borderColor: 'divider',
            }}
          >
            <Typography variant="h6" color="text.secondary">
              Google Maps Integration
              <br />
              (Add your Google Maps embed code here)
            </Typography>
          </Box>
        </Box>
      </Container>
    </Box>
  );
};

export default Contact;

